// Split webhook binary files into separate items
// Generate unified dealId from all filenames

const item = $input.first();
const body = item.json.body || {};
const binary = item.binary || {};

// Parse filenames from body
let filenames = [];
try {
  filenames = JSON.parse(body.filenames || '[]');
} catch (e) {
  // If not JSON, try to get from binary
  filenames = Object.values(binary).map(b => b.fileName);
}

// Generate unified deal ID from sorted filenames
const combinedNames = filenames.sort().join('|');
const dealId = Buffer.from(combinedNames).toString('base64').replace(/[^a-zA-Z0-9]/g, '').slice(0, 20);

// Get all binary keys
const binaryKeys = Object.keys(binary).filter(k => k.startsWith('data'));

if (binaryKeys.length === 0) {
  throw new Error('No binary files found in webhook request');
}

// Create one item per file
const items = binaryKeys.map((key, index) => {
  const binaryData = binary[key];
  const extension = (binaryData.fileExtension || '').toLowerCase();

  return {
    json: {
      dealId: dealId,
      sourceFile: binaryData.fileName,
      fileType: extension,
      mimeType: binaryData.mimeType,
      fileIndex: index,
      totalFiles: binaryKeys.length
    },
    binary: {
      data: binaryData
    }
  };
});

return items;

// Handle both paths: from cache hit or from aggregated embeddings
  const items = $input.all();

  let dealId;

  // Check if coming from cache hit path
  if (items[0]?.json?.cacheHit === true) {
    dealId = items[0].json.dealId;
  } else {
    // Coming from aggregate embeddings path
    const dealIdArray = items[0]?.json?.deal_id;
    dealId = Array.isArray(dealIdArray) ? dealIdArray[0] : (dealIdArray || 'unknown');
  }

  return [{
    json: {
      dealId,
      filesProcessed: items[0]?.json?.vectorCount || (Array.isArray(items[0]?.json?.deal_id)
   ? items[0].json.deal_id.length : 1),
      fromCache: items[0]?.json?.cacheHit || false,
      timestamp: new Date().toISOString()
    }
  }];

