const raw = $input.first()?.json ?? {};
const data = raw.output && typeof raw.output === 'object' ? raw.output : raw;

const companyProfile = data.company_profile && typeof data.company_profile === 'object' ? data.company_profile : {};
const financials = data.financials && typeof data.financials === 'object' ? data.financials : {};
const analysis = data.analysis && typeof data.analysis === 'object' ? data.analysis : {};
const margins = financials.margins && typeof financials.margins === 'object' ? financials.margins : {};

const isPresent = (value) => value !== null && value !== undefined && String(value).trim() !== '';

let companyName = 'Not Available';
if (isPresent(companyProfile.company_name)) companyName = String(companyProfile.company_name);

let industry = 'Not Available';
if (isPresent(companyProfile.industry)) industry = String(companyProfile.industry);

let location = 'Not Available';
if (isPresent(companyProfile.location)) location = String(companyProfile.location);

let employeeCount = 'Not Available';
if (typeof companyProfile.employee_count === 'number' && Number.isFinite(companyProfile.employee_count) && companyProfile.employee_count !== 0) {
  employeeCount = companyProfile.employee_count.toLocaleString('en-US');
} else if (isPresent(companyProfile.employee_count) && String(companyProfile.employee_count).trim() !== '0') {
  employeeCount = String(companyProfile.employee_count).trim();
}

const escapeHtml = (value) => String(value)
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');

let revenueTableRows = '<tr><td colspan="3" class="na-value">No revenue data available</td></tr>';
if (Array.isArray(financials.revenue_history) && financials.revenue_history.length > 0) {
  const rows = [];
  for (const row of financials.revenue_history) {
    const year = isPresent(row?.year) ? String(row.year) : 'N/A';

    let amount = 'Not Available';
    if (typeof row?.amount === 'number' && Number.isFinite(row.amount) && row.amount !== 0) {
      amount = row.amount.toLocaleString('en-US');
    } else if (isPresent(row?.amount) && String(row.amount).trim() !== '0') {
      amount = String(row.amount).trim();
    }

    const currency = isPresent(row?.currency) ? String(row.currency) : 'USD';
    rows.push('<tr><td>' + escapeHtml(year) + '</td><td>' + escapeHtml(amount) + '</td><td>' + escapeHtml(currency) + '</td></tr>');
  }
  revenueTableRows = rows.join('');
}

let ebitda = 'Not Available';
if (typeof financials.ebitda === 'number' && Number.isFinite(financials.ebitda) && financials.ebitda !== 0) {
  ebitda = financials.ebitda.toLocaleString('en-US');
} else if (isPresent(financials.ebitda) && String(financials.ebitda).trim() !== '0') {
  ebitda = String(financials.ebitda).trim();
}

const grossMargin = isPresent(margins.gross_margin) ? String(margins.gross_margin) : 'Not Available';
const netMargin = isPresent(margins.net_margin) ? String(margins.net_margin) : 'Not Available';
const ebitdaMargin = isPresent(margins.ebitda_margin) ? String(margins.ebitda_margin) : 'Not Available';

const businessModel = isPresent(analysis.business_model) ? String(analysis.business_model) : 'Not Available';
const investmentThesis = isPresent(analysis.investment_thesis) ? String(analysis.investment_thesis) : 'Not Available';
const customerConcentration = isPresent(analysis.customer_concentration) ? String(analysis.customer_concentration) : 'Not Available';

let riskListItems = '<li class="risk-item"><span class="risk-icon">-</span><span class="risk-text">No specific risks identified in the document</span></li>';
if (Array.isArray(analysis.key_risks)) {
  const riskRows = [];
  let riskIndex = 1;
  for (const risk of analysis.key_risks) {
    if (!isPresent(risk)) continue;
    riskRows.push('<li class="risk-item"><span class="risk-icon">' + String(riskIndex) + '</span><span class="risk-text">' + escapeHtml(String(risk)) + '</span></li>');
    riskIndex += 1;
  }
  if (riskRows.length > 0) {
    riskListItems = riskRows.join('');
  }
}

let dealId = 'N/A';
const ctx = $('Prepare Analysis Context').first();
if (ctx?.json?.dealId) dealId = String(ctx.json.dealId);

const reportDate = DateTime.now().toFormat("MMMM dd, yyyy 'at' HH:mm");

return [{
  json: {
    companyName,
    industry,
    location,
    employeeCount,
    revenueTableRows,
    ebitda,
    grossMargin,
    netMargin,
    ebitdaMargin,
    businessModel,
    investmentThesis,
    riskListItems,
    customerConcentration,
    dealId,
    reportDate,
  },
}];

