const input = $input.first()?.json || {};
const dealId = input.dealId ? String(input.dealId) : 'unknown';

const countryRaw = String(input.location || input.country || input.hqCountry || 'United States').trim();
const countryKey = countryRaw.toLowerCase();
const countryMap = {
  us: { name: 'United States', code: 'us', locale: 'en-US' },
