  au: { name: 'Australia', code: 'au', locale: 'en-AU' },
  australia: { name: 'Australia', code: 'au', locale: 'en-AU' },
};
const countryInfo = countryMap[countryKey] || { name: countryRaw || 'United States', code: 'us', locale: 'en-US' };

let uploaded = [];
try {
  uploaded = $('Split Uploaded Files + Build Deal ID').all().map((item) => item.json || {});
} catch (error) {}

const filenames = [...new Set(uploaded.map((row) => String(row.sourceFile || '').trim()).filter(Boolean))];
const genericWords = new Set([
  'teaser', 'pitch', 'deck', 'presentation', 'financial', 'model', 'appendix', 'report', 'company', 'profile',
  'data', 'room', 'deal', 'final', 'draft', 'rev', 'revised', 'version', 'copy', 'updated', 'new', 'signed',
  'executive', 'summary', 'overview', 'confidential', 'cim', 'im', 'memo', 'management', 'seller', 'buyer',
  'nda', 'appendices', 'attachment', 'file', 'doc', 'docs'
]);
const monthWords = new Set(['jan','january','feb','february','mar','march','apr','april','may','jun','june','jul','july','aug','august','sep','sept','september','oct','october','nov','november','dec','december']);
const invalidTlds = new Set(['pdf', 'ppt', 'pptx', 'doc', 'docx', 'xls', 'xlsx']);

const stripExtension = (value) => String(value || '').replace(/\.[a-z0-9]{2,5}$/i, '');
const titleCase = (value) => String(value || '').split(' ').filter(Boolean).map((token) => token.charAt(0).toUpperCase() + token.slice(1)).join(' ');
const extractDomains = (value) => {
  const cleaned = stripExtension(value);
  const matches = String(cleaned || '').match(/\b(?:[a-z0-9-]+\.)+[a-z]{2,}\b/gi) || [];
  return matches.map((entry) => entry.toLowerCase()).filter((entry) => !invalidTlds.has(entry.split('.').pop()));
};
const normalizeCandidate = (value) => stripExtension(value)
  .replace(/[|_]+/g, ' ')
  .replace(/[()\[\]]/g, ' ')
  .replace(/[–—-]+/g, ' ')
  .replace(/\b(v\d+|ver\d+|version\d+|final|draft|copy|signed|updated|new)\b/gi, ' ')
  .replace(/\b(19|20)\d{2}\b/g, ' ')
  .replace(/[^a-zA-Z0-9.& ]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();
const meaningfulTokens = (value) => normalizeCandidate(value)
  .split(/\s+/)
  .map((token) => token.trim())
  .filter(Boolean)
  .filter((token) => token.length > 1)
  .filter((token) => !monthWords.has(token.toLowerCase()))
  .filter((token) => !/^(jan|january|feb|february|mar|march|apr|april|may|jun|june|jul|july|aug|august|sep|sept|september|oct|october|nov|november|dec|december)(19|20)?\d{2}$/i.test(token))
  .filter((token) => !genericWords.has(token.toLowerCase()))
  .filter((token) => !/^\d+$/.test(token))
  .filter((token) => !/^(19|20)\d{2}$/.test(token));

const tokenRows = filenames.map((name) => ({
  raw: name,
  tokens: meaningfulTokens(name),
  domains: extractDomains(name),
}));
const tokenCounts = {};
for (const row of tokenRows) {
  for (const token of new Set(row.tokens.map((entry) => entry.toLowerCase()))) {
    tokenCounts[token] = (tokenCounts[token] || 0) + 1;
  }
}

let consensusTokens = [];
if (tokenRows.length > 1) {
  const minSupport = Math.min(tokenRows.length, 2);
  consensusTokens = Object.entries(tokenCounts)
    .filter(([, count]) => count >= minSupport)
    .sort((a, b) => b[1] - a[1] || a[0].localeCompare(b[0]))
    .map(([token]) => token);
}

const candidateRows = tokenRows.map((row) => {
  let score = row.tokens.reduce((sum, token) => sum + ((tokenCounts[token.toLowerCase()] || 0) * 10), 0);
  if (row.domains.length > 0) score -= 25;
  if (row.tokens.length === 1) score += 12;
  if (row.tokens.length >= 2) score += 8;
  return {
    raw: row.raw,
    normalized: titleCase(row.tokens.slice(0, 4).join(' ')),
    tokens: row.tokens,
    score,
  };
}).filter((row) => row.tokens.length > 0);
candidateRows.sort((a, b) => b.score - a.score || a.normalized.localeCompare(b.normalized));

let companyTokens = [];
if (consensusTokens.length > 0) {
  companyTokens = consensusTokens.slice(0, 3);
} else if (candidateRows[0]) {
  companyTokens = candidateRows[0].tokens.slice(0, 4).map((token) => token.toLowerCase());
}

if (companyTokens.length === 0 && filenames[0]) {
  companyTokens = normalizeCandidate(filenames[0]).split(/\s+/).filter(Boolean).slice(0, 3).map((token) => token.toLowerCase());
}

let companyNameGuess = titleCase(companyTokens.join(' ')).trim() || 'Target Company';
const genericFilenameFlag = companyTokens.length < 1;
const mentionedDomains = [...new Set(filenames.flatMap(extractDomains))];
const seedConfidence = mentionedDomains.length > 0 ? 'high' : (companyTokens.length >= 2 ? 'medium' : 'low');
const searchQuery = `${companyNameGuess} official website ${countryInfo.name}`.trim();
const fallbackSearchQuery = `${companyNameGuess} company ${countryInfo.name}`.trim();

return [{
  json: {
    ...input,
    dealId,
    companyNameGuess,
    primaryCompanyName: companyNameGuess,
    sourceFilenames: filenames,
    mentionedDomains,
    genericFilenameFlag,
    seedConfidence,
    hqCountry: countryInfo.name,
    searchCountryCode: countryInfo.code,
    searchLocale: countryInfo.locale,
    searchQuery,
    fallbackSearchQuery,
    tokenConsensus: consensusTokens.slice(0, 5),
  }
}];

const seed = $('Derive Company Seed').first().json || {};
const payload = $json || {};

const blockedDomains = new Set([
  'google.com', 'www.google.com', 'linkedin.com', 'www.linkedin.com', 'facebook.com', 'www.facebook.com',
  'instagram.com', 'www.instagram.com', 'x.com', 'twitter.com', 'wikipedia.org', 'www.wikipedia.org',
