]);
const blockedFragments = ['linkedin', 'facebook', 'instagram', 'twitter', 'x.com', 'wikipedia', 'crunchbase', 'glassdoor', 'indeed', 'zoominfo', 'pitchbook', 'bloomberg', 'mapquest', 'yelp', 'tripadvisor', 'directory', 'listing', 'provider', 'portal', 'forum', 'reddit', 'news'];
const blockedSuffixes = ['.gov', '.edu'];

const normalizeDomain = (value) => {
  let raw = String(value || '').trim().toLowerCase();
  if (!raw) return '';
  raw = raw.replace(/^https?:\/\//, '').replace(/^www\./, '');
  raw = raw.split('/')[0].split('?')[0].split('#')[0].trim();
  if (!raw || !raw.includes('.')) return '';
  const tld = raw.split('.').pop();
  if (['pdf', 'ppt', 'pptx', 'doc', 'docx', 'xls', 'xlsx'].includes(tld)) return '';
  return raw;
};
const normalizeUrl = (value) => {
  const domain = normalizeDomain(value);
  return domain ? `https://${domain}` : '';
};
const isBlockedDomain = (domain) => {
  if (!domain || blockedDomains.has(domain)) return true;
  if (blockedSuffixes.some((suffix) => domain.endsWith(suffix))) return true;
  if (domain.includes('.gov.') || domain.includes('.edu.')) return true;
  if (domain.split('.').length > 4) return true;
  return blockedFragments.some((fragment) => domain.includes(fragment));
};
const companyTokens = String(seed.companyNameGuess || '').toLowerCase().split(/\s+/).filter((token) => token.length > 2);
const scoreSearchHit = (title, snippet, domain) => {
  const haystack = `${title} ${snippet} ${domain}`.toLowerCase();
  let score = 0;
  const matchedTokens = companyTokens.filter((token) => haystack.includes(token));
  score += matchedTokens.length * 14;
  if (haystack.includes('official')) score += 15;
  if (haystack.includes('home')) score += 8;
  if (haystack.includes('company')) score += 6;
  if (haystack.includes((seed.hqCountry || '').toLowerCase())) score += 5;
  if (blockedFragments.some((fragment) => haystack.includes(fragment))) score -= 50;
  return score;
};

const candidates = [];
const seen = new Set();
const addCandidate = (domainOrUrl, source, baseScore, extra = {}) => {
  const domain = normalizeDomain(domainOrUrl);
  if (!domain || isBlockedDomain(domain)) return;
  if (!/^[a-z0-9.-]+\.[a-z]{2,}$/i.test(domain)) return;
  if (seen.has(domain)) return;
  seen.add(domain);
  candidates.push({
    dealId: seed.dealId,
    companyNameGuess: seed.companyNameGuess || 'Target Company',
    hqCountry: seed.hqCountry || 'United States',
    candidateDomain: domain,
    url: normalizeUrl(domain),
    source,
    sourceSignals: [source],
    baseScore,
    resolutionReason: `candidate_from_${source}`,
    ...extra,
  });
};

for (const domain of seed.mentionedDomains || []) addCandidate(domain, 'doc_domain', 65);

const organic = payload.results?.[0]?.content?.results?.results?.organic || payload.results?.[0]?.content?.results?.organic || [];
const searchResults = Array.isArray(organic) && organic.length > 0 ? organic : [];
for (const row of searchResults.slice(0, 8)) {
  const title = String(row.title || row.favicon_text || '');
  const snippet = String(row.desc || row.snippet || '');
  const url = row.url || row.url_shown || '';
  const domain = normalizeDomain(url);
  if (!domain) continue;
  const searchScore = scoreSearchHit(title, snippet, domain);
  if (searchScore < 10) continue;
  addCandidate(url, 'search_result', 30 + Math.min(searchScore, 25), {
    resultTitle: title.slice(0, 240),
    resultSnippet: snippet.slice(0, 500),
    serpScore: searchScore,
  });
}

const normalizeBase = (value) => String(value || '')
  .toLowerCase()
  .replace(/\b(inc|ltd|limited|llc|corp|corporation|co|group|holdings|company|pte|pt|cv|tbk|technologies|technology|solutions|management)\b/g, ' ')
  .replace(/[^a-z0-9\s]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();
const guessedBases = [];
const cleaned = normalizeBase(seed.companyNameGuess);
const parts = cleaned.split(' ').filter(Boolean);
if (parts.length) guessedBases.push(parts.join(''));
if (parts.length >= 2) guessedBases.push(parts[0]);
const tlds = ['.com', '.co'];
if ((seed.searchCountryCode || '').toLowerCase() === 'id') tlds.push('.co.id', '.id');
if ((seed.searchCountryCode || '').toLowerCase() === 'sg') tlds.push('.com.sg', '.sg');
if ((seed.searchCountryCode || '').toLowerCase() === 'gb') tlds.push('.co.uk');
for (const base of [...new Set(guessedBases)].slice(0, 2)) {
  if (base.length < 4) continue;
  for (const tld of tlds) addCandidate(`${base}${tld}`, 'guessed', 10);
}

candidates.sort((a, b) => (b.baseScore || 0) - (a.baseScore || 0) || a.candidateDomain.localeCompare(b.candidateDomain));
return candidates.slice(0, 3).map((candidate, index) => ({ json: { ...candidate, candidateRank: index + 1 } }));

const seed = $('Derive Company Seed').first().json || {};
const candidate = $('Iterate Domain Candidates').item.json || {};
const payload = $json || {};
const rawError = payload.error ? String(payload.error) : '';
const rawContent = payload.results?.[0]?.content || payload.content || payload.markdown || payload.html || payload.text || '';
const content = typeof rawContent === 'string' ? rawContent : JSON.stringify(rawContent);
const lc = content.toLowerCase();

const companyName = String(seed.companyNameGuess || '').trim();
const companyLc = companyName.toLowerCase();
const companyTokens = companyLc.split(/\s+/).filter((token) => token.length > 2);

let verificationScore = 0;
const reasons = [];

if (companyLc && lc.includes(companyLc)) {
  verificationScore += 35;
  reasons.push('exact_company_name_match');
} else {
  const matchedTokens = companyTokens.filter((token) => lc.includes(token)).length;
  if (matchedTokens >= Math.max(1, Math.min(2, companyTokens.length))) {
    verificationScore += 20;
    reasons.push('partial_company_token_match');
  }
}

const hqCountry = String(seed.hqCountry || '').toLowerCase();
if (hqCountry && lc.includes(hqCountry)) {
  verificationScore += 10;
  reasons.push('country_match');
}

if (lc.includes('about') || lc.includes('company') || lc.includes('products') || lc.includes('services')) {
  verificationScore += 8;
  reasons.push('corporate_page_signal');
}

if (content.length > 500) {
  verificationScore += 5;
  reasons.push('sufficient_content_length');
} else if (content.length < 120) {
  verificationScore -= 20;
  reasons.push('thin_content_penalty');
}

if (rawError) {
  verificationScore -= 50;
  reasons.push('request_error_penalty');
}

const negativePatterns = [
  'linkedin', 'crunchbase', 'wikipedia', 'facebook', 'instagram', 'x.com', 'twitter',
  'domain for sale', 'buy this domain', 'parked domain', 'coming soon', 'not found', '404'
];
for (const pattern of negativePatterns) {
  if (lc.includes(pattern)) {
    verificationScore -= 25;
    reasons.push(`negative:${pattern}`);
  }
}

const finalScore = Math.max(0, Math.min(100, Number(candidate.baseScore || 0) + verificationScore));
let verifyStatus = 'reject';
if (finalScore >= 80) verifyStatus = 'verified';
else if (finalScore >= 55) verifyStatus = 'probable';

return [{
  json: {
    ...candidate,
    verificationScore,
    finalScore,
    verifyStatus,
    verifyPreview: content.slice(0, 1200),
    resolutionReason: reasons.length ? reasons.join(',') : (candidate.resolutionReason || 'low_confidence_match'),
  }
}];

const rows = Array.isArray($json.domainCandidates) ? $json.domainCandidates : [];
const fallback = $('Derive Company Seed').first().json || {};

if (rows.length === 0) {
  return [{
    json: {
      dealId: fallback.dealId || 'unknown',
      companyNameGuess: fallback.companyNameGuess || 'Target Company',
      hqCountry: fallback.hqCountry || 'United States',
      canonicalDomain: '',
      canonicalUrl: '',
      finalScore: 0,
      canonicalStatus: 'reject',
      resolutionReason: 'no_candidates_found',
      targetUrl: ''
    }
  }];
}

const sortedRows = [...rows].sort((a, b) => (b.finalScore || 0) - (a.finalScore || 0));
const best = sortedRows[0];
const canonicalStatus = best.verifyStatus || ((best.finalScore || 0) >= 80 ? 'verified' : ((best.finalScore || 0) >= 55 ? 'probable' : 'reject'));
const baseUrl = String(best.url || '').replace(/\/$/, '');
const pathSet = canonicalStatus === 'verified' ? ['', '/about'] : [''];

return pathSet.map((path, index) => ({
  json: {
    dealId: best.dealId || fallback.dealId,
    companyNameGuess: best.companyNameGuess || fallback.companyNameGuess,
    hqCountry: best.hqCountry || fallback.hqCountry || 'United States',
    canonicalDomain: best.candidateDomain || '',
    canonicalUrl: best.url || '',
    finalScore: best.finalScore || 0,
    canonicalStatus,
    resolutionReason: best.resolutionReason || 'best_scoring_candidate',
    sourceSignals: best.sourceSignals || [],
    targetUrl: `${baseUrl}${path}`,
    targetIndex: index + 1,
  }
}));

const src = $('Iterate Enrichment URLs').item.json;
const payload = $json || {};
const rawError = payload.error ? String(payload.error) : '';
const content = payload.results?.[0]?.content || payload.content || payload.markdown || payload.html || payload.text || '';
const text = typeof content === 'string' ? content : JSON.stringify(content);

const url = src.targetUrl || src.canonicalUrl || '';
let evidenceType = 'commercial_risk';
if (url.includes('/about') || url.includes('/company') || url.includes('/team')) evidenceType = 'company_profile';

let confidence = 0.3;
if ((src.canonicalStatus || '') === 'verified') confidence = 0.8;
else if ((src.canonicalStatus || '') === 'probable') confidence = 0.55;
if (text.length > 1000) confidence += 0.1;
confidence = Math.max(0.2, Math.min(0.95, confidence));

return [{
  json: {
    dealId: src.dealId,
    canonicalUrl: src.canonicalUrl,
    canonicalStatus: src.canonicalStatus || 'reject',
    resolutionReason: src.resolutionReason || 'unclassified',
    sourceSignals: src.sourceSignals || [],
    sourceUrl: url,
    evidenceType,
    claim: text.slice(0, 4000),
    confidence: Number(confidence.toFixed(2)),
    geoUsed: src.hqCountry || 'United States',
    capturedAt: new Date().toISOString(),
    status: rawError ? 'error' : (text.length > 0 ? 'success' : 'failed'),
    rawError,
    markdown: text
  }
}];

const items = $json.externalEvidence || [];
const canonicalStatus = items[0]?.canonicalStatus || $('Select Canonical Domain').first().json.canonicalStatus || 'reject';
if (canonicalStatus === 'reject') {
  return [{
    json: {
      dealId: items[0]?.dealId || $('Prepare Analysis Context').first().json.dealId,
      externalEvidence: [],
      failedEvidence: items,
      externalSourcesCount: 0,
      failedEvidenceCount: items.length,
      evidenceCoverage: 0,
      confidenceSummary: 'low',
      evidenceGatePass: false,
      evidenceCategories: { profileCount: 0, riskCount: 0 },
      canonicalStatus,
      generatedAt: new Date().toISOString()
    }
  }];
}
const success = items.filter((item) => item.status === 'success');
const failed = items.filter((item) => item.status !== 'success');
const coverage = items.length === 0 ? 0 : success.length / items.length;
let confidenceSummary = 'low';
if (coverage >= 0.75) confidenceSummary = 'high';
else if (coverage >= 0.4) confidenceSummary = 'medium';
const profileCount = success.filter((item) => item.evidenceType.includes('profile')).length;
const riskCount = success.filter((item) => item.evidenceType.includes('risk') || item.evidenceType.includes('commercial')).length;
return [{
  json: {
    dealId: items[0]?.dealId || $('Prepare Analysis Context').first().json.dealId,
    externalEvidence: success,
    failedEvidence: failed,
    externalSourcesCount: success.length,
    failedEvidenceCount: failed.length,
    evidenceCoverage: Number(coverage.toFixed(2)),
    confidenceSummary,
    evidenceGatePass: success.length >= 1,
    evidenceCategories: { profileCount, riskCount },
    canonicalStatus,
    generatedAt: new Date().toISOString()
  }
}];

const base = $('Prepare Analysis Context').first().json;
let metrics = {
  externalSourcesCount: 0,
  evidenceCoverage: 0,
  confidenceSummary: 'low',
  evidenceGatePass: false,
  evidenceCategories: { profileCount: 0, riskCount: 0 },
};
try {
  metrics = { ...metrics, ...$('Evidence Coverage Metrics').first().json };
} catch (error) {}
const canonical = $('Select Canonical Domain').first().json || {};
const canonicalStatus = canonical.canonicalStatus || 'reject';
if (canonicalStatus === 'reject') {
  metrics.externalSourcesCount = 0;
  metrics.evidenceCoverage = 0;
  metrics.confidenceSummary = 'low';
  metrics.evidenceGatePass = false;
}
return [{
  json: {
    ...base,
    externalSourcesCount: metrics.externalSourcesCount || 0,
    evidenceCoverage: metrics.evidenceCoverage || 0,
    confidenceSummary: metrics.confidenceSummary || 'low',
    evidenceGatePass: metrics.evidenceGatePass || false,
    evidenceCategories: metrics.evidenceCategories || { profileCount: 0, riskCount: 0 },
    canonicalStatus,
    canonicalDomain: canonical.canonicalDomain || '',
    resolutionReason: canonical.resolutionReason || 'no_valid_domain',
    sourceSignals: canonical.sourceSignals || [],
    externalEvidenceSummary: canonicalStatus === 'reject'
      ? 'external_sources=0; coverage=0; confidence=low; canonical_status=reject'
      : `external_sources=${metrics.externalSourcesCount || 0}; coverage=${metrics.evidenceCoverage || 0}; confidence=${metrics.confidenceSummary || 'low'}; canonical_status=${canonicalStatus}`
  }
}];

const report = { ...($input.first()?.json || {}) };
const evidence = $('Prepare AI Input with Evidence').first().json;

report.evidenceCoverage = evidence.evidenceCoverage ?? 0;
report.externalSourcesCount = evidence.externalSourcesCount ?? 0;
report.confidenceSummary = evidence.confidenceSummary || 'low';
report.evidenceDisclaimer = report.evidenceCoverage < 0.4
  ? 'External evidence coverage is limited. Conclusions should be interpreted with caution.'
  : '';

return [{ json: report }];

const merged = $input.first().json || {};
const aiInput = $('Prepare AI Input with Evidence').first().json || {};
const rawAi = $('Run Due Diligence AI Analysis').first().json || {};
const structured = rawAi.output && typeof rawAi.output === 'object' ? rawAi.output : rawAi;
const companyProfile = structured.company_profile && typeof structured.company_profile === 'object' ? structured.company_profile : {};
const financials = structured.financials && typeof structured.financials === 'object' ? structured.financials : {};
const analysis = structured.analysis && typeof structured.analysis === 'object' ? structured.analysis : {};
const margins = financials.margins && typeof financials.margins === 'object' ? financials.margins : {};

