const keyRisks = Array.isArray(analysis.key_risks)
  ? analysis.key_risks.filter((risk) => risk !== null && risk !== undefined && String(risk).trim() !== '').map((risk) => String(risk))
  : [];

const hasExternalEvidence = (aiInput.externalSourcesCount || 0) > 0 && aiInput.canonicalStatus !== 'reject';
const responseStatus = hasExternalEvidence ? 'success' : 'partial_success';

return [{
  json: {
    success: true,
    responseStatus,
    dealId: aiInput.dealId || 'unknown',
    fileName: merged.fileName || '',
    publicUrl: merged.publicUrl || '',
    output: {
      company_profile: {
        company_name: companyProfile.company_name ?? 'Not Available',
        industry: companyProfile.industry ?? 'Not Available',
