        key_risks: keyRisks,
        customer_concentration: analysis.customer_concentration ?? 'Not Available',
      }
    },
    evidence: {
      evidenceCoverage: hasExternalEvidence ? (aiInput.evidenceCoverage || 0) : 0,
      externalSourcesCount: hasExternalEvidence ? (aiInput.externalSourcesCount || 0) : 0,
      confidenceSummary: hasExternalEvidence ? (aiInput.confidenceSummary || 'low') : 'low',
      canonicalStatus: aiInput.canonicalStatus || 'reject',
      resolutionReason: aiInput.resolutionReason || 'no_valid_domain',
      evidenceDisclaimer: aiInput.canonicalStatus === 'reject'
        ? 'External website could not be confidently verified. Report uses internal document evidence only.'
        : ((aiInput.evidenceCoverage || 0) < 0.4
            ? 'External evidence coverage is limited. Validate manually for investment-critical decisions.'
            : ''),
    }
  }
}];

const stats = $input.first().json;
  const originalItems = $('Split Uploaded Files + Build Deal ID').all();
  const dealId = originalItems[0]?.json?.dealId;

  if (stats.error || !stats.namespaces || typeof stats.namespaces !== 'object') {
    return originalItems.map(item => ({
      json: {
        ...item.json,
        cacheHit: false,
        cacheStatus: 'unknown',
        cacheReason: stats.error || 'namespace lookup unavailable'
      },
      binary: item.binary
    }));
  }

  const namespaceExists = stats.namespaces && stats.namespaces[dealId];
  const vectorCount = namespaceExists ? stats.namespaces[dealId].vectorCount : 0;

  if (vectorCount > 0) {
    return [{
      json: {
        dealId: dealId,
        cacheHit: true,
        cacheStatus: 'hit',
        vectorCount: vectorCount,
        message: `Cache HIT: ${vectorCount} vectors found`
      }
    }];
  }

  return originalItems.map(item => ({
    json: {
      ...item.json,
      cacheHit: false,
      cacheStatus: 'miss'
    },
    binary: item.binary
  }));
